files.content:
.mrg-center {
  --mrg-center-maximum: 100%;
  display: flex;
  flex-direction: column;
  inline-size: 100%;
  min-block-size: 0;
  min-inline-size: 0;
  text-align: start;
}

.mrg-center > * {
  max-inline-size: min(100%, var(--mrg-center-maximum));
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-center[data-axis="inline"],
.mrg-center[data-axis="both"] {
  align-items: center;
}

.mrg-center[data-axis="block"],
.mrg-center[data-axis="both"] {
  justify-content: center;
}

.mrg-center[data-maximum="prose"] {
  --mrg-center-maximum: var(--mrg-semantic-container-prose);
}

.mrg-center[data-maximum="content"] {
  --mrg-center-maximum: var(--mrg-semantic-container-content);
}

.mrg-center[data-text="center"] {
  text-align: center;
}

import { forwardRef, type HTMLAttributes } from "react";

import "./center.css";

export type CenterAxis = "inline" | "block" | "both";
export type CenterMaximum = "none" | "prose" | "content";

export interface CenterProps extends HTMLAttributes<HTMLDivElement> {
  readonly axis?: CenterAxis;
  /** Constrains direct children with a semantic max while preserving a 100% narrow bound. */
  readonly maximum?: CenterMaximum;
  readonly text?: "start" | "center";
}

function joinCenterClassName(className: string | undefined): string {
  return className === undefined || className.trim().length === 0
    ? "mrg-center"
    : `mrg-center ${className}`;
}

export const Center = forwardRef<HTMLDivElement, CenterProps>(function Center(
  { axis = "both", className, maximum = "none", text = "start", ...nativeProps },
  forwardedRef,
) {
  return (
    <div
      {...nativeProps}
      ref={forwardedRef}
      className={joinCenterClassName(className)}
      data-axis={axis}
      data-maximum={maximum}
      data-slot="center"
      data-text={text}
    />
  );
});

Center.displayName = "Center";
